let form=document.getElementById("contact-form"),statusEl=document.getElementById("contact-status"),submitBtn=document.getElementById("contact-submit");form?.addEventListener("submit",async t=>{t.preventDefault();var t=new FormData(form),e=(t.get("name")||"").toString().trim(),s=(t.get("email")||"").toString().trim(),a=(t.get("message")||"").toString().trim();if(e&&s&&a){s="Lead-"+e.replace(/\s+/g,"");t.append("subject",s),submitBtn.disabled=!0,submitBtn.classList.add("opacity-60"),statusEl.textContent="Enviando...";try{var n=await(await fetch(form.action,{method:"POST",body:t})).json();statusEl.textContent=n.message||(n.success?"Mensagem enviada.":"Erro ao enviar."),n.success&&form.reset()}catch(t){console.error(t),statusEl.textContent="Erro de conexão. Tente novamente mais tarde."}finally{submitBtn.disabled=!1,submitBtn.classList.remove("opacity-60")}}else statusEl.textContent="Por favor, preencha todos os campos."});